def _nav(active: str) -> str:
    logo_uri = image_data_uri(Path(__file__).resolve().parents[2] / "assets" / "truecadence_mark_cutout.png")
    items = [
        ("骑手档案", "骑手档案", "骑手档案", "骑手资料"),
        ("上传与诊断", "上传与诊断", "上传与诊断", "上传 FIT"),
        ("功率能力数据", "专业数据", "专业数据", "功率画像"),
        ("今日训练建议", "训练驾驶舱", "训练驾驶舱", "首页简报"),
        ("训练计划", "训练计划", "训练计划", "本周课表"),
        ("今日补给", "今日补给", "状态与恢复", "营养补给"),
        ("状态与恢复", "状态与恢复", "状态与恢复", "恢复睡眠"),
    ]
    links = "".join(f'<a target="_self" class="{ "active" if active_key == active else "" }" href="{_url(nav, sub)}">{label}</a>' for label, active_key, nav, sub in items)
    return f"""<aside class="tc-side">
<div class="tc-brand"><div class="tc-side-symbol" aria-hidden="true"><img src="{logo_uri}" alt="" /></div><div class="tc-side-shine-word"><span data-letter="T">T</span><span data-letter="r">r</span><span data-letter="u">u</span><span data-letter="e">e</span><span data-letter="C">C</span><span data-letter="a">a</span><span data-letter="d">d</span><span data-letter="e">e</span><span data-letter="n">n</span><span data-letter="c">c</span><span data-letter="e">e</span></div><div class="tc-side-slogan">慢下来 · 成为自己的节奏</div></div>
<nav class="tc-nav">{links}</nav>
<div class="tc-side-foot"><a target="_self" href="{_url('帮助 · 隐私 · 更新','首页')}">帮助 · 隐私 · 更新</a></div>
</aside>"""


def _wrap(active: str, title: str, body: str) -> None:
    _css()
    body_html = dedent(body).strip()
    html = f"""<div class="tc-app"><div class="tc-bg-lines"></div><div class="tc-shell">
{_nav(active)}
<main class="tc-main">
<div class="tc-top"><div class="tc-top-left"><span class="pill range">{title}</span></div><div class="tc-top-right"><a target="_self" class="pill" href="#tc-account-plan-modal-layer">账号与套餐</a></div></div>
<div class="speed"></div>
{body_html}
</main>
</div></div>"""
    st.markdown(html, unsafe_allow_html=True)
    render_account_plan_modal()
